#include <bits/stdc++.h>
using namespace std;
const int maxn=13,mod=1e8;
#define int long long
int dp[maxn][1<<maxn],bit[maxn];
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	int n,m;
	cin>>n>>m;
	for(int i=1; i<=n; i++) {
		for(int j=0; j<m; j++) {
			int x;
			cin>>x;
			bit[i]=bit[i]*2+x;
		}
	}
	dp[0][0]=1;
	for(int i=1; i<=n; i++) {
		for(int j=0; j<(1<<m); j++) {
			if((j&(j<<1))!=0||(j&bit[i])!=j) {
				continue;
			}
			for(int k=0; k<(1<<m); k++) {
				if((j&k)!=0) {
					continue;
				}
				dp[i][j]=(dp[i][j]+dp[i-1][k])%mod;
			}
		}
	}
	int ans=0;
	for(int i=0;i<(1<<m);i++){
		ans=(ans+dp[n][i])%mod;
	}
	cout<<ans;
	return 0;
}
